import 'dart:convert';
import 'package:http/http.dart' as http;
import 'package:shared_preferences/shared_preferences.dart';

class ApiClient {
  static const String baseUrl = 'https://api.example.com';
  static String? _token;
  static final http.Client _client = http.Client();

  static Future<void> initialize() async {
    final prefs = await SharedPreferences.getInstance();
    _token = prefs.getString('auth_token');
  }

  static Future<http.Response> _makeRequest(
    String endpoint, {
    String method = 'GET',
    Map<String, String>? headers,
    dynamic body,
  }) async {
    final url = '$baseUrl$endpoint';
    final authHeaders = {
      'Authorization': 'Bearer $_token',
      'Content-Type': 'application/json',
    };

    if (headers != null) {
      authHeaders.addAll(headers);
    }

    try {
      switch (method) {
        case 'GET':
          return await _client.get(Uri.parse(url), headers: authHeaders);
        case 'POST':
          return await _client.post(
            Uri.parse(url),
            headers: authHeaders,
            body: jsonEncode(body),
          );
        case 'PUT':
          return await _client.put(
            Uri.parse(url),
            headers: authHeaders,
            body: jsonEncode(body),
          );
        case 'DELETE':
          return await _client.delete(Uri.parse(url), headers: authHeaders);
        default:
          throw Exception('Unsupported HTTP method');
      }
    } on Exception {
      rethrow;
    }
  }

  static Future<void> login(String username, String password) async {
    final response = await _makeRequest(
      '/auth/login',
      method: 'POST',
      body: {'username': username, 'password': password},
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      _token = data['token'];
      
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('auth_token', _token!);
    } else {
      throw Exception('Login failed');
    }
  }

  static Future<Map<String, dynamic>> getUserProfile() async {
    final response = await _makeRequest('/profile');
    
    if (response.statusCode == 200) {
      return jsonDecode(response.body);
    } else {
      throw Exception('Failed to fetch profile');
    }
  }

  static Future<Map<String, dynamic>> syncData(
    Map<String, dynamic> localData,
  ) async {
    final response = await _makeRequest(
      '/sync',
      method: 'POST',
      body: localData,
    );

    if (response.statusCode == 200) {
      return jsonDecode(response.body);
    } else {
      throw Exception('Sync failed');
    }
  }

  static Future<void> logout() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.remove('auth_token');
    _token = null;
  }

  static Future<void> dispose() async {
    await _client.close();
  }
}